531		if project.Spec.ProviderSecretRef != "" {
532			var secret corev1.Secret
533			if err := r.Get(ctx, client.ObjectKey{Namespace: task.Namespace, Name: project.Spec.ProviderSecretRef}, &secret); err != nil {
534				if !apierrors.IsNotFound(err) {
535					return release, err
536				}
537			} else {
538				lim := r.Deps.Budget.ForSecret(string(secret.UID), r.defaultsForSecret(&secret))
539				if lim != nil {
540					rsv := lim.Reserve()
541					d := rsv.Delay()
542					if d > 0 {
543						rsv.Cancel()
544						budget.ProviderRateLimitHitsTotal.WithLabelValues(project.Name).Inc()
545						patch := client.MergeFrom(task.DeepCopy())
546						meta.SetStatusCondition(&task.Status.Conditions, metav1.Condition{
547							Type:               tideprojectv1alpha1.ConditionReconciling,
548							Status:             metav1.ConditionTrue,
549							Reason:             "RateLimited",
550							Message:            fmt.Sprintf("Rate-limit bucket exhausted; requeuing after %s", d),
551							LastTransitionTime: metav1.Now(),
552						})
553						if err := r.Status().Patch(ctx, task, patch); err != nil {
554							return release, err
555						}
556						// Return a sentinel error that encodes the requeue delay so
557						// reconcileDispatch can translate it back to a ctrl.Result.
558						return release, &rateLimitedError{delay: d}
559					}
560					// d == 0: token consumed. Hold the reservation so any error
561					// before Job Create returns the token to the bucket.
562					heldReservation = rsv
563				}
564			}
565		}
566	
567		return release, nil
568	}
